-- core_ref_currency
-- ============================================================
BEGIN EXECUTE IMMEDIATE 'DROP TABLE core_ref_currency CASCADE CONSTRAINTS'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
CREATE TABLE core_ref_currency (
    code        VARCHAR2(3)  NOT NULL,
    char_code   VARCHAR2(10),  -- ba'zi qiymatlarda Kirill belgi bor (bayt > belgi)
    name        VARCHAR2(300),
    scale       NUMBER(2),
